# Bulk file renamer
import os
def rename_files(directory, prefix):
    for i, f in enumerate(os.listdir(directory)):
        ext = os.path.splitext(f)[1]
        new_name = f'{prefix}_{i+1}{ext}'
        os.rename(os.path.join(directory, f),
                  os.path.join(directory, new_name))

