# OBSERVER — notify multiple objects of changes
# Use for: event systems, notifications, pub/sub
class EventManager:
    def __init__(self):
        self.listeners = {}

    def subscribe(self, event, callback):
        self.listeners.setdefault(event, []).append(callback)

    def emit(self, event, data):
        for callback in self.listeners.get(event, []):
            callback(data)

events = EventManager()
events.subscribe('order', lambda d: print(f'Email: {d}'))
events.subscribe('order', lambda d: print(f'SMS: {d}'))
events.emit('order', 'Order #123 confirmed')

