# O — Open/Closed (open for extension, closed for modification)
# Use typing.Protocol for duck typing + type safety
from typing import Protocol

class PaymentMethod(Protocol):
    def process(self, amount: float) -> bool: ...

class UPIPayment:
    def process(self, amount: float) -> bool:
        print(f'UPI: {amount}')
        return True

class CardPayment:
    def process(self, amount: float) -> bool:
        print(f'Card: {amount}')
        return True

# Adding new payment = new class, NO modification to existing code
class CryptoPayment:
    def process(self, amount: float) -> bool:
        print(f'Crypto: {amount}')
        return True

# D — Dependency Injection
# WRONG: hard-coded dependency
class OrderService:
    def __init__(self):
        self.payment = UPIPayment()  # Tightly coupled!

# RIGHT: inject dependency
class OrderService:
    def __init__(self, payment: PaymentMethod):
        self.payment = payment  # Loosely coupled!

# Can use any payment method:
order1 = OrderService(UPIPayment())
order2 = OrderService(CardPayment())
order3 = OrderService(CryptoPayment())

